sql:
SELECT COUNT(element_id) AS element_count
FROM cinematic_elements
WHERE model_id = 1;

SELECT status, COUNT(*) AS model_count
FROM cinematic_models
GROUP BY status;

SELECT name AS model_name
FROM cinematic_models
ORDER BY model_name;

SELECT name, status
FROM cinematic_models
ORDER BY created_at DESC;

SELECT name, created_at AS birth_date
FROM cinematic_models
ORDER BY created_at DESC;

SELECT name
FROM cinematic_models
ORDER BY name;
